        sum += nums(i)
        val rem = ((sum % k) + k) % k
        if (prefixRemainder.contains(rem)) {
            val prev = prefixRemainder(rem)
            segments += ((prev + 1, i.toLong))
        }
        prefixRemainder(rem) = i.toLong
    }

    if (segments.isEmpty) {
        return nums.sum
    }

    val sortedSegments = segments.sortBy(seg => (seg._2, seg._1))

