        if (seg._1 > lastEnd) {
            var sumSeg = 0L
            for (i <- seg._1.toInt to seg._2.toInt) {
                sumSeg += nums(i)
            }
            removedSum += sumSeg
            lastEnd = seg._2
        }
    }

    nums.sum - removedSum
}
